def calculate_covariance_matrix(vectors: list[list[float]]) -> list[list[float]]:
    n_features = len(vectors)
    n_obs = len(vectors[0])

    means = [sum(v) / n_obs for v in vectors]

    def covariance(v1, v2, mean1, mean2):
        return sum((v1[i] - mean1) * (v2[i] - mean2) for i in range(n_obs)) / (n_obs - 1)

    return [
        [covariance(vectors[i], vectors[j], means[i], means[j]) for j in range(n_features)]
        for i in range(n_features)
    ]

