import numpy as np

def calculate_covariance_matrix(vectors: list[list[float]]) -> list[list[float]]:
    matrix = np.array(vectors)  # shape: (n_features, n_obs)
    cov = np.cov(matrix)        # ddof=1 by default (Bessel's correction)
    return cov.tolist()
